#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Route {
    Home,
    Billing,
    AdminPanel,
    Support,
    Reports,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Export,
    SuspendUser,
}

pub fn decide(role: Role, route: Route, action: Action) -> &'static str {
    match action {
        Action::View => match route {
            Route::Home | Route::Support => "allow",
            Route::Billing => {
                if matches!(role, Role::Member | Role::Moderator | Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            Route::AdminPanel => {
                if matches!(role, Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            Route::Reports => {
                if matches!(role, Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
        },
        Action::Edit => match route {
            Route::Home => {
                if matches!(role, Role::Member | Role::Moderator | Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            Route::Support => {
                if matches!(role, Role::Moderator | Role::Admin) {
                    "allow"
                } else {
                    "review"
                }
            }
            Route::Billing => {
                if matches!(role, Role::Member | Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            Route::AdminPanel | Route::Reports => {
                if matches!(role, Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
        },
        Action::Export => match route {
            Route::Reports => {
                if matches!(role, Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            Route::Billing => {
                if matches!(role, Role::Member | Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            _ => "deny",
        },
        Action::SuspendUser => match route {
            Route::AdminPanel => {
                if matches!(role, Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            Route::Support => {
                if matches!(role, Role::Moderator | Role::Admin) {
                    "allow"
                } else {
                    "deny"
                }
            }
            _ => "deny",
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn guests_can_only_view_public_pages() {
        assert_eq!(decide(Role::Guest, Route::Home, Action::View), "allow");
        assert_eq!(decide(Role::Guest, Route::Support, Action::View), "allow");
        assert_eq!(decide(Role::Guest, Route::Billing, Action::View), "deny");
        assert_eq!(decide(Role::Guest, Route::Home, Action::Edit), "deny");
    }

    #[test]
    fn moderators_can_view_reports_but_cannot_export_them() {
        assert_eq!(decide(Role::Moderator, Route::Reports, Action::View), "allow");
        assert_eq!(decide(Role::Moderator, Route::Reports, Action::Export), "deny");
    }

    #[test]
    fn members_need_review_for_support_edits() {
        assert_eq!(decide(Role::Member, Route::Support, Action::Edit), "review");
    }

    #[test]
    fn moderators_may_edit_billing_but_members_may_not_export_it() {
        assert_eq!(decide(Role::Moderator, Route::Billing, Action::Edit), "allow");
        assert_eq!(decide(Role::Member, Route::Billing, Action::Export), "review");
    }

    #[test]
    fn suspend_user_requires_stricter_routing() {
        assert_eq!(decide(Role::Moderator, Route::AdminPanel, Action::SuspendUser), "review");
        assert_eq!(decide(Role::Moderator, Route::Support, Action::SuspendUser), "allow");
        assert_eq!(decide(Role::Admin, Route::Support, Action::SuspendUser), "review");
        assert_eq!(decide(Role::Admin, Route::AdminPanel, Action::SuspendUser), "allow");
    }
}

