use std::collections::HashMap;

#[derive(Clone, Debug)]
struct Config {
    endpoint: String,
    file: String,
    color: bool,
    retries: u32,
    timeout: u32,
}

#[derive(Default)]
struct PartialConfig {
    endpoint: Option<String>,
    file: Option<String>,
    color: Option<bool>,
    retries: Option<u32>,
    timeout: Option<u32>,
}

fn parse_bool(s: &str) -> Option<bool> {
    match s {
        "1" | "true" | "yes" | "on" => Some(true),
        "0" | "false" | "no" | "off" => Some(false),
        _ => None,
    }
}

fn parse_u32(s: &str) -> Option<u32> {
    s.parse::<u32>().ok()
}

fn from_pairs(pairs: &[(&str, &str)]) -> PartialConfig {
    let mut p = PartialConfig::default();
    for (k, v) in pairs {
        match *k {
            "endpoint" => {
                if !v.is_empty() {
                    p.endpoint = Some((*v).to_string());
                }
            }
            "file" => {
                if !v.is_empty() {
                    p.file = Some((*v).to_string());
                }
            }
            "color" => p.color = parse_bool(v),
            "retries" => p.retries = parse_u32(v),
            "timeout" => p.timeout = parse_u32(v),
            _ => {}
        }
    }
    p
}

fn merge(defaults: Config, env: PartialConfig, file: PartialConfig, cli: PartialConfig) -> Config {
    let mut cfg = defaults;

    if let Some(v) = cli.endpoint.or(file.endpoint).or(env.endpoint) {
        cfg.endpoint = v;
    }
    if let Some(v) = cli.file.or(file.file).or(env.file) {
        cfg.file = v;
    }
    if let Some(v) = cli.color.or(file.color).or(env.color) {
        if v {
            cfg.color = true;
        }
    }
    if let Some(v) = cli.retries.or(file.retries).or(env.retries) {
        if v > 0 {
            cfg.retries = v;
        }
    }
    if let Some(v) = cli.timeout.or(file.timeout).or(env.timeout) {
        if v > 0 {
            cfg.timeout = v;
        }
    }

    cfg
}

fn render(label: &str, cfg: &Config) -> String {
    format!(
        "{} endpoint={} file={} color={} retries={} timeout={}",
        label, cfg.endpoint, cfg.file, cfg.color, cfg.retries, cfg.timeout
    )
}

fn main() {
    let defaults = Config {
        endpoint: "https://default.example".to_string(),
        file: "/tmp/default.log".to_string(),
        color: true,
        retries: 3,
        timeout: 30,
    };

    let case_a_env = from_pairs(&[("endpoint", ""), ("color", "true"), ("retries", "0")]);
    let case_a_file = from_pairs(&[("file", "/srv/file.log"), ("timeout", "0")]);
    let case_a_cli = from_pairs(&[("endpoint", ""), ("retries", "0")]);

    let case_b_env = from_pairs(&[("endpoint", "https://env.example"), ("color", "maybe"), ("retries", "1")]);
    let case_b_file = from_pairs(&[("endpoint", "https://file.example"), ("file", ""), ("color", "false"), ("timeout", "10")]);
    let case_b_cli = from_pairs(&[]);

    let case_c_env = from_pairs(&[("endpoint", "https://env.example"), ("file", "/tmp/env.log"), ("color", "false"), ("retries", "8")]);
    let case_c_file = from_pairs(&[("endpoint", "https://file.example"), ("color", "true"), ("timeout", "5")]);
    let case_c_cli = from_pairs(&[("endpoint", "https://cli.example"), ("file", "/tmp/cli.log"), ("retries", "2"), ("timeout", "0")]);

    let out = vec![
        render("caseA", &merge(defaults.clone(), case_a_env, case_a_file, case_a_cli)),
        render("caseB", &merge(defaults.clone(), case_b_env, case_b_file, case_b_cli)),
        render("caseC", &merge(defaults, case_c_env, case_c_file, case_c_cli)),
    ];

    let mut seen = HashMap::new();
    for line in out {
        *seen.entry(line.clone()).or_insert(0usize) += 1;
        println!("{}", line);
    }
}

