use std::collections::BTreeMap;

#[derive(Clone, Debug)]
enum Value {
    Text(String),
    Bool(bool),
    Num(i32),
}

impl Value {
    fn render(&self) -> String {
        match self {
            Value::Text(s) => s.clone(),
            Value::Bool(b) => b.to_string(),
            Value::Num(n) => n.to_string(),
        }
    }
}

fn merge(
    defaults: &BTreeMap<&'static str, Value>,
    file: &BTreeMap<&'static str, Option<Value>>,
    env: &BTreeMap<&'static str, Option<Value>>,
    cli: &BTreeMap<&'static str, Option<Value>>,
) -> BTreeMap<&'static str, Value> {
    let mut out = defaults.clone();

    for (k, v) in file {
        if let Some(v) = v.clone() {
            out.insert(*k, v);
        }
    }

    for (k, v) in cli {
        if let Some(v) = v.clone() {
            out.insert(*k, v);
        }
    }

    for (k, v) in env {
        if let Some(v) = v.clone() {
            match &v {
                Value::Text(s) if s.is_empty() => {}
                Value::Bool(false) => {}
                Value::Num(0) => {}
                _ => {
                    out.insert(*k, v);
                }
            }
        }
    }

    out
}

fn main() {
    let defaults = BTreeMap::from([
        ("endpoint", Value::Text("https://default.local".into())),
        ("mode", Value::Text("safe".into())),
        ("color", Value::Bool(true)),
        ("retry", Value::Num(3)),
        ("trace", Value::Bool(false)),
    ]);

    let file = BTreeMap::from([
        ("endpoint", Some(Value::Text("https://file.local".into()))),
        ("mode", Some(Value::Text("compact".into()))),
        ("color", Some(Value::Bool(false))),
        ("retry", Some(Value::Num(1))),
    ]);

    let env = BTreeMap::from([
        ("endpoint", Some(Value::Text("".into()))),
        ("mode", Some(Value::Text("verbose".into()))),
        ("color", Some(Value::Bool(true))),
        ("retry", Some(Value::Num(0))),
        ("trace", Some(Value::Bool(true))),
    ]);

    let cli = BTreeMap::from([
        ("endpoint", None),
        ("mode", Some(Value::Text("".into()))),
        ("color", Some(Value::Bool(false))),
        ("retry", Some(Value::Num(0))),
        ("trace", Some(Value::Bool(false))),
    ]);

    let merged = merge(&defaults, &file, &env, &cli);
    for key in ["endpoint", "mode", "color", "retry", "trace"] {
        println!("{}={}", key, merged.get(key).unwrap().render());
    }
}

