    let score_s = parts[1].trim();
    let dept = parts[2].trim();

    if name.len() < 3 || !name.chars().all(|c| c.is_ascii_lowercase()) {
        return None;
    }
    if dept.is_empty() || !dept.chars().all(|c| c.is_ascii_lowercase()) {
        return None;
    }
    if score_s.starts_with('0') || !score_s.chars().all(|c| c.is_ascii_digit()) {
        return None;
    }
    let score: u16 = score_s.parse().ok()?;
    if !(10..=999).contains(&score) {
        return None;
    }

    Some((name.to_string(), score, dept.to_string()))
}

