    for line in INPUT.lines() {
        if let Some((name, level, region)) = parse_valid(line) {
            rows.push(format!("{}|{}|{}", name, region, level));
        }
    }

    println!("VALID {}", rows.len());
    for row in rows {
        println!("{}", row);
    }
}

