#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Route {
    Home,
    Profile,
    AdminPanel,
    ReportQueue,
    Billing,
    Login,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Approve,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Decision {
    Allow,
    Deny,
    Redirect(Route),
    Require2FA,
}

pub fn decide(role: Role, route: Route, action: Action, has_2fa: bool) -> Decision {
    match route {
        Route::Login => Decision::Allow,
        Route::Home => Decision::Allow,
        Route::Profile => match action {
            Action::View => Decision::Allow,
            Action::Edit => match role {
                Role::Guest => Decision::Redirect(Route::Login),
                _ => Decision::Allow,
            },
            _ => Decision::Deny,
        },
        Route::AdminPanel => match role {
            Role::Admin => Decision::Allow,
            Role::Moderator => Decision::Allow,
            Role::Member => Decision::Redirect(Route::Home),
            Role::Guest => Decision::Redirect(Route::Login),
        },
        Route::ReportQueue => match action {
            Action::View => match role {
                Role::Moderator | Role::Admin => Decision::Allow,
                _ => Decision::Deny,
            },
            Action::Approve => match role {
                Role::Admin => Decision::Allow,
                Role::Moderator => Decision::Allow,
                _ => Decision::Deny,
            },
            _ => Decision::Deny,
        },
        Route::Billing => match action {
            Action::View => match role {
                Role::Admin => Decision::Allow,
                Role::Member => Decision::Allow,
                _ => Decision::Deny,
            },
            Action::Edit => match role {
                Role::Admin => Decision::Allow,
                _ => Decision::Deny,
            },
            _ => Decision::Deny,
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn guests_get_redirected_for_profile_edit() {
        assert_eq!(
            decide(Role::Guest, Route::Profile, Action::Edit, false),
