        assert_eq!(
            decide(Role::Moderator, Route::AdminPanel, Action::View, false),
            Decision::Require2FA
        );
        assert_eq!(
            decide(Role::Moderator, Route::AdminPanel, Action::View, true),
            Decision::Allow
        );
    }

    #[test]
