fn build_report(rows: &[Row]) -> String {
    let mut by_region: BTreeMap<&str, BTreeMap<&str, f64>> = BTreeMap::new();

    for row in rows {
        if !row.active || row.amount <= 0.0 {
            continue;
        }
        let dept_map = by_region.entry(row.region).or_default();
        *dept_map.entry(row.dept).or_insert(0.0) += row.amount;
    }

    let mut regions: Vec<(&str, Vec<(&str, f64)>, f64)> = by_region
        .into_iter()
        .filter_map(|(region, dept_map)| {
            let mut depts: Vec<(&str, f64)> = dept_map.into_iter().filter(|(_, total)| *total > 0.0).collect();
            if depts.is_empty() {
                return None;
            }
            depts.sort_by(|a, b| b.1.total_cmp(&a.1).then_with(|| a.0.cmp(b.0)));
            let region_total: f64 = depts.iter().map(|(_, total)| *total).sum();
            if region_total <= 0.0 {
                None
            } else {
                Some((region, depts, region_total))
            }
        })
        .collect();

    regions.sort_by(|a, b| b.2.total_cmp(&a.2).then_with(|| a.0.cmp(b.0)));

    let mut out = String::from("REGION REPORT\n");
    for (region, depts, region_total) in regions {
        out.push_str(&format!("{} | total={:.2} | departments={}\n", region, region_total, depts.len()));
        for (dept, total) in depts {
            out.push_str(&format!("  {}: {:.2}\n", dept, total));
        }
    }

    out.trim_end().to_string()
}

