use std::collections::HashMap;

#[derive(Clone, Debug)]
struct Config {
    name: String,
    retries: u32,
    verbose: bool,
    color: String,
}

fn parse_kv(input: &str) -> HashMap<String, String> {
    let mut map = HashMap::new();
    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        if let Some((k, v)) = line.split_once('=') {
            map.insert(k.trim().to_string(), v.trim().to_string());
        }
    }
    map
}

fn parse_bool(s: &str) -> Option<bool> {
    match s {
        "true" | "1" | "yes" | "on" => Some(true),
        "false" | "0" | "no" | "off" => Some(false),
        _ => None,
    }
}

fn merge(defaults: &Config, file: &HashMap<String, String>, env: &HashMap<String, String>, cli: &HashMap<String, String>) -> Config {
    let mut cfg = defaults.clone();

    if let Some(v) = file.get("name") {
        if !v.is_empty() {
            cfg.name = v.clone();
        }
    }
    if let Some(v) = file.get("retries") {
        if let Ok(n) = v.parse::<u32>() {
            cfg.retries = n;
        }
    }
    if let Some(v) = file.get("verbose") {
        if let Some(b) = parse_bool(v) {
            if b {
                cfg.verbose = b;
            }
        }
    }
    if let Some(v) = file.get("color") {
        if !v.is_empty() {
            cfg.color = v.clone();
        }
    }

    if let Some(v) = env.get("APP_NAME") {
        if !v.is_empty() {
            cfg.name = v.clone();
        }
    }
    if let Some(v) = env.get("APP_RETRIES") {
        if let Ok(n) = v.parse::<u32>() {
            if n > 0 {
                cfg.retries = n;
            }
        }
    }
    if let Some(v) = env.get("APP_VERBOSE") {
        if let Some(b) = parse_bool(v) {
            if b {
                cfg.verbose = true;
            }
        }
    }
    if let Some(v) = env.get("APP_COLOR") {
        if !v.is_empty() {
            cfg.color = v.clone();
        }
    }

    if let Some(v) = cli.get("name") {
        if !v.is_empty() {
            cfg.name = v.clone();
        }
    }
    if let Some(v) = cli.get("retries") {
        if let Ok(n) = v.parse::<u32>() {
            if n > 0 {
                cfg.retries = n;
            }
        }
    }
    if let Some(v) = cli.get("verbose") {
        if let Some(b) = parse_bool(v) {
            if b {
                cfg.verbose = true;
            }
        }
    }
    if let Some(v) = cli.get("color") {
        if !v.is_empty() {
            cfg.color = v.clone();
        }
    }

    cfg
}

fn main() {
    let defaults = Config {
        name: "guest".to_string(),
        retries: 3,
        verbose: true,
        color: "blue".to_string(),
    };

    let file = parse_kv("name=file-user\nretries=9\nverbose=true\ncolor=green\n");
    let env = parse_kv("APP_NAME=env-user\nAPP_RETRIES=0\nAPP_VERBOSE=false\nAPP_COLOR=\n");
    let cli = parse_kv("name=\nretries=0\nverbose=false\ncolor=\n");

    let cfg = merge(&defaults, &file, &env, &cli);
    println!("name={}", cfg.name);
