#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Staff,
    Admin,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Route {
    Home,
    Dashboard,
    AdminPanel,
    Billing,
    Audit,
    Support,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Refund,
    Impersonate,
}

pub fn decide(role: Role, route: Route, action: Action, flagged: bool, emergency: bool) -> &'static str {
    use Action::*;
    use Role::*;
    use Route::*;

    match route {
        Home => "allow",
        Dashboard => match action {
            View => if role == Guest { "deny" } else { "allow" },
            Edit => if role == Admin { "allow" } else { "review" },
            _ => "deny",
        },
        AdminPanel => match action {
            View => if role == Admin { "allow" } else { "deny" },
            Edit => if role == Admin { "allow" } else { "deny" },
            Impersonate => if role == Admin { "allow" } else { "deny" },
            Refund => "deny",
        },
        Billing => match action {
            View => if role == Member || role == Admin { "allow" } else { "deny" },
            Edit => if role == Admin { "allow" } else { "deny" },
            Refund => if role == Admin { "allow" } else { "deny" },
            Impersonate => "deny",
        },
        Audit => match action {
            View => if role == Staff || role == Admin { "allow" } else { "deny" },
            Edit => if role == Admin { "allow" } else { "deny" },
            Refund => "deny",
            Impersonate => "deny",
        },
        Support => match action {
            View => if flagged { "review" } else { "allow" },
            Edit => if role == Staff || role == Admin { "allow" } else { "deny" },
            Refund => if role == Staff { "review" } else { "deny" },
            Impersonate => if emergency && role == Staff { "allow" } else { "deny" },
        },
    }
}

