use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScoreRow {
    pub player: String,
    pub score: i32,
    pub solved: u32,
    pub penalty: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedRow {
    pub rank: usize,
    pub player: String,
    pub score: i32,
    pub solved: u32,
    pub penalty: u32,
}

pub fn leaderboard(rows: &[ScoreRow]) -> Vec<RankedRow> {
    let mut merged: Vec<ScoreRow> = rows.to_vec();

    merged.sort_by(|a, b| {
        b.score.cmp(&a.score)
            .then_with(|| a.player.cmp(&b.player))
    });

    merged
        .into_iter()
        .enumerate()
        .map(|(idx, row)| RankedRow {
            rank: idx + 1,
            player: row.player,
            score: row.score,
            solved: row.solved,
            penalty: row.penalty,
        })
        .collect()
}

